        const double x4r = *(&in_re[4 * K + k]), x4i = *(&in_im[4 * K + k]);
        const double s1r = (x1r + x4r), s1i = (x1i + x4i);
        const double s2r = (x2r + x3r), s2i = (x2i + x3i);
        const double d1r = (x1r - x4r), d1i = (x1i - x4i);
        const double d2r = (x2r - x3r), d2i = (x2i - x3i);
        *(&out_re[0 * K + k]) = (x0r + (s1r + s2r));
        *(&out_im[0 * K + k]) = (x0i + (s1i + s2i));
        const double t0r = (x0r - cK3 * (s1r + s2r)), t0i = (x0i - cK3 * (s1i + s2i));
        const double t1r = (cK0 * (s1r - s2r)), t1i = (cK0 * (s1i - s2i));
        const double p1r = (t0r + t1r), p1i = (t0i + t1i);
        const double p2r = (t0r - t1r), p2i = (t0i - t1i);
        const double Ti = (cK2 * d2i + (cK1 * d1i)), Tu = (cK2 * d2r + (cK1 * d1r));
        const double Tk = ((cK1 * d2i) - cK2 * d1i), Tv = ((cK1 * d2r) - cK2 * d1r);
        *(&out_re[1 * K + k]) = (p1r + Ti);
        *(&out_im[1 * K + k]) = (p1i - Tu);
        *(&out_re[4 * K + k]) = (p1r - Ti);
        *(&out_im[4 * K + k]) = (p1i + Tu);
        *(&out_re[2 * K + k]) = (p2r - Tk);
        *(&out_im[2 * K + k]) = (p2i + Tv);
        *(&out_re[3 * K + k]) = (p2r + Tk);
